// Extrai dados relevantes do payload da Evolution API v2
// Log completo do payload para diagnóstico
const fullPayload = $input.first().json;
console.log('=== PAYLOAD COMPLETO ===', JSON.stringify(fullPayload));

const body = fullPayload.body || fullPayload;

// A Evolution API v2 envia o instanceName em diferentes campos dependendo da versão
const instanceName = body.instance 
  || body.instanceName 
  || body.data?.instance 
  || body.sender
  || '';

console.log('instanceName extraído:', instanceName);

const data = body.data || {};
const key = data.key || {};
const remoteJid = key.remoteJid || '';

// Suporte a diferentes formatos de mensagem
const message = data.message?.conversation 
  || data.message?.extendedTextMessage?.text 
  || data.message?.imageMessage?.caption
  || '';

const fromMe = key.fromMe || false;
const pushName = data.pushName || body.pushName || '';
const phone = remoteJid.replace('@s.whatsapp.net', '');

console.log('Extraído:', { instanceName, phone, message: message.substring(0, 50), fromMe });

return [{ instanceName, phone, message, pushName, remoteJid, fromMe }];

